#include <stdio.h>
#include <stdint.h>
const long long MOD = 998244353LL;
long long modpow(long long a, long long e) {
    long long r = 1;
    a %= MOD;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, K; scanf("%lld %lld", &N, &K);
        long long exp = ( (K % (MOD-1)) * ((N-1) % (MOD-1)) ) % (MOD-1);
        printf("%lld\n", modpow(2, exp));
    }
    return 0;
}

